cat > /tmp/mcp-explore.csx << 'EOF'
#!/usr/bin/env dotnet-script

#r "nuget: ModelContextProtocol, 1.3.0"

using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

var asm = Assembly.Load("ModelContextProtocol");

Console.WriteLine("=== ALL EXPORTED TYPES ===\n");
var types = asm.GetExportedTypes().OrderBy(t => t.Namespace).ThenBy(t => t.Name).ToList();
foreach (var t in types)
{
    Console.WriteLine($"{t.Namespace}.{t.Name}");
}

Console.WriteLine("\n\n=== ATTRIBUTES ===\n");
var attrTypes = types.Where(t => t.BaseType?.FullName == "System.Attribute").ToList();
foreach (var attr in attrTypes)
{
    Console.WriteLine($"{attr.Namespace}.{attr.Name}");
    var props = attr.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    foreach (var prop in props)
    {
        Console.WriteLine($"  - {prop.Name}: {prop.PropertyType.Name}");
    }
}

Console.WriteLine("\n\n=== BUILDER/HOSTING TYPES ===\n");
var hostTypes = types.Where(t => 
    t.Name.Contains("Builder") || 
    t.Name.Contains("Host") || 
    t.Name.Contains("Server") ||
    t.Name.Contains("Stdio")).ToList();
foreach (var t in hostTypes)
{
    Console.WriteLine($"\n{t.FullName}");
    Console.WriteLine($"  Base: {t.BaseType?.FullName}");

    var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
        .Where(m => !m.IsSpecialName).ToList();
    foreach (var m in methods.Take(10))
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  - {m.Name}({parms}): {m.ReturnType.Name}");
    }
    if (methods.Count > 10) Console.WriteLine($"  ... and {methods.Count - 10} more methods");
}

Console.WriteLine("\n\n=== MESSAGE/CONTENT TYPES ===\n");
var messageTypes = types.Where(t => 
    t.Name.Contains("Message") || 
    t.Name.Contains("Content") ||
    t.Name.Contains("Role") ||
    t.Name.Contains("Tool") ||
    t.Name.Contains("Prompt")).ToList();
foreach (var t in messageTypes.OrderBy(t => t.Name).Take(30))
{
    Console.WriteLine($"{t.FullName}");
}

Console.WriteLine("\n\n=== KEY INTERFACES ===\n");
var interfaces = types.Where(t => t.IsInterface).ToList();
foreach (var i in interfaces)
{
    Console.WriteLine($"\n{i.FullName}");
    var methods = i.GetMethods();
    foreach (var m in methods.Take(5))
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  - {m.Name}({parms}): {m.ReturnType.Name}");
    }
    if (methods.Length > 5) Console.WriteLine($"  ... and {methods.Length - 5} more methods");
}

EOF
